import{_ as t,o as a,c as n,a0 as i}from"./chunks/framework.D68qFDln.js";const g=JSON.parse('{"title":"Tech Generic Docs","description":"","frontmatter":{"title":"Tech Generic Docs"},"headers":[],"relativePath":"docs/tech.md","filePath":"en/docs/tech.md"}'),s={name:"docs/tech.md"};function o(l,e,r,c,h,d){return a(),n("div",null,e[0]||(e[0]=[i(`<h1 id="tech-generic-docs" tabindex="-1">Tech Generic Docs <a class="header-anchor" href="#tech-generic-docs" aria-label="Permalink to &quot;Tech Generic Docs&quot;">​</a></h1><h2 id="adding-an-event" tabindex="-1">Adding an event <a class="header-anchor" href="#adding-an-event" aria-label="Permalink to &quot;Adding an event&quot;">​</a></h2><p>Files for event cards are under <code>content/&lt;language&gt;/events/</code>. Filenames start with underscore (<code>_</code>) and ends with <code>.md</code>. You can put whatever you want in the middle, but it is recommended to choose a filename related to the title of the event. The format of each file is as below, where content between the two <code>---</code>s is called the <strong>frontmatter</strong> and content after it is called the <strong>main content</strong>.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">title: &#39;event title&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time: &#39;ISO-8601 time with time zone, for example 2024-12-20T23:59:59+00:00&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># If there is no link, delete this section</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">link:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  type: &#39;link text&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  url: &#39;link target&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Content for non-link tags, can be more than one</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">community:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &#39;tag text&#39;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &#39;tag text&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># If there is no location, delete this section</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">location: &#39;location&#39;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image: &#39;poster image filename, see below for details&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Poster content in text format</span></span></code></pre></div><p>Poster images are under the directory of <code>content/public/assets/events</code>. For example, if you put the image in <code>content/public/assets/events/xxx.png</code>, you write <code>xxx.png</code> in the <code>image</code> section above.</p><p>To accomodate people for whom reading images is inconvenient, please write down <strong>all</strong> text content in the image as-is, and do not miss anything. If there are QR codes or other machine-readable graphs, please write out the content it represents (e.g. links) in the main content. For example, if there is a QR code in the image which is a link pointing to <code>https://example.com/abcdef</code> after decoding, and there is text &quot;please scan QR code to register&quot; in the image, then you write in the main content: <code>please [scan QR code to register](https://example.com/abcdef)</code>. For another example, if there is a QR code same as the one mentioned above, but there is no text in the image suitable to be a link text, then you add an extra paragraph at the end of the main content and write: <code>[registration link](https://example.com/abcdef)</code>.</p><p>You can use HTML in the <code>title</code> and <code>community</code> items in the frontmatter and also in the main content. For best reading experience, it is especially recommended to care about the following two cases:</p><ul><li>When you need to use an abbreviation, use the <code>&lt;abbr&gt;</code> tag, whose format is <code>&lt;abbr title=&quot;full name&quot;&gt;abbreviation&lt;/abbr&gt;</code>, for example <code>&lt;abbr title=&quot;One Among Us&quot;&gt;OAU&lt;/abbr&gt;</code>.</li><li>When you want to use <span class="allCaps">all-caps</span> to write something that is not an abbreviation, first consider whether it is really necessary. If not, use a format that is not all-caps. If necessary (for example, &quot;it is all caps in the image&quot;), use <code>&lt;span class=&quot;allCaps&quot;&gt;Normal case format&lt;/span&gt;</code>, for example <code>&lt;span class=&quot;allCaps&quot;&gt;One Among Us&lt;/span&gt;</code>. This way it will be displayed in all-caps but it will remain normal case format if copied.</li></ul><p>When creating the event file, please consider the text of your poster.</p><ul><li>If there is a different image version of each language, create a <code>md</code> file for each language and write the content of the images into the Markdown main content for the corresponding language.</li><li>If there is only one image, then write the text content into the Markdown main content for only one language. In the files for other languages, use the special marker <code>&lt;!--@include: @/other-filename --&gt;</code> to reference it. The filename is based in the <code>content</code> directory. For example, for <code>content/en/events/_2024-tdor-broadcast-event-1.md</code>, the corresponding filename for the other language is <code>content/zh-Hans/events/_2024-跨性别纪念日晚会-1.md</code>. Thus, you write <code>&lt;!--@include: @/zh-Hans/events/_2024-跨性别纪念日晚会-1.md --&gt;</code> in the main content.</li><li>For simplicity, if there is a main language in the image, choose it as the directory for the source file. Otherwise, choose a language randomly.</li><li>Write the frontmatter for the Markdown files for each language in the corresponding language.</li></ul><h2 id="write-commit-messages" tabindex="-1">Write Commit Messages <a class="header-anchor" href="#write-commit-messages" aria-label="Permalink to &quot;Write Commit Messages&quot;">​</a></h2><p>Effective Feb 20, 2023, we adopt the commit message convention as follows for all One Among Us repositories:</p><blockquote><p>[*] Do something</p></blockquote><p>The message should be written in English. Starting with a mark symbol in square brackets and separated by a space character, the headline should be a imperative sentence describing what you do and end without punctuation marks. Detailed descriptions are not mandatory but recommended if you find it complicated. We follow the 72-column line-wrapping rule.</p><p><strong>Marks</strong></p><blockquote><p>[+] Add</p><p>[-] Remove</p><p>[U] Update</p><p>[O] Optimize</p><p>[F] Fix</p><p>[S] Modify style</p><p>[M] Move (also [M] Modify by convention but [U] Modify is recommended)</p><p>[R] Refactor</p><p>[T] Test</p><p>[D] Tweak documentation</p><p>[B] Backup</p><p>[PR] Merge commit of pull request</p></blockquote><p><strong>Examples</strong></p><blockquote><p>[+] Add entry for sauricat</p><p>[U] Update photos for sauricat</p><p>[F] Fix punctuation</p></blockquote><p><em>Under Construction...</em></p>`,19)]))}const m=t(s,[["render",o]]);export{g as __pageData,m as default};
